VALUES
  ('pukao-d1056197-moex-00097', 'pukao-d1056197', 'pukao-d1056197-moex-113-d1a761c9', 'sub-pukao-d1056197-01', NULL, 'single_choice', '關於因公共設施設置或管理有欠缺，人民請求國家賠償之敘述，下列何者錯誤？', '["賠償義務機關，係指公共設施之管理機關", "管理機關，係指法令所定之管理機關或依法代為管理之機關", "設施雖非由國家設置，但事實上由其管理，並直接供公共或公務目的使用，仍屬國家賠償法所稱之 公共設施", "公共設施因設置或管理，致人民人身自由受損害者，國家不負損害賠償責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:48+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "408", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('pukao-d1056197-moex-00098', 'pukao-d1056197', 'pukao-d1056197-moex-113-d1a761c9', 'sub-pukao-d1056197-01', NULL, 'single_choice', '關於國家賠償之敘述，下列何者正確？', '["國家賠償請求權人，只能請求所受損害，不得請求其所失利益", "國家負損害賠償責任者，應以金錢為之。但以回復原狀為適當者，得依請求，回復損害發生前原狀", "國家賠償之請求權，自損害發生時起，因2年間不行使而消滅", "外國人為被害人時，不得請求國家賠償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:48+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "408", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('pukao-d1056197-moex-00099', 'pukao-d1056197', 'pukao-d1056197-moex-113-d1a761c9', 'sub-pukao-d1056197-01', NULL, 'single_choice', '關於國家賠償法所規定之公務員國家賠償責任，下列敘述何者正確？', '["給付行政措施，不生公務員國家賠償責任", "受委託行使公權力者，於行使公權力時，亦適用公務員國家賠償責任", "為求人民權利保障之完整性，縱使公務員並無故意或過失，亦構成公務員國家賠償責任", "為使人民權利獲得全面性之保障，故公務員之不法行為與損害發生間，不以具有因果關係為必要"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:48+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "408", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('pukao-d1056197-moex-00100', 'pukao-d1056197', 'pukao-d1056197-moex-113-d1a761c9', 'sub-pukao-d1056197-01', NULL, 'single_choice', '有關行政裁量，下列敘述何者正確？', '["主管機關基於對外國人原國籍之厭惡，否准其歸化申請，乃裁量之濫用", "行政機關於訂定裁罰基準後，即不得於個案裁處時再為裁量", "法規授予行政機關裁量時，法院即不得審查該裁量決定", "法規授予行政機關裁量時，上級機關亦不得訂定統一之裁量基準"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:48+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "408", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('pukao-d1056197-moex-00101', 'pukao-d1056197', 'pukao-d1056197-moex-112-d1a761c9', 'sub-pukao-d1056197-01', NULL, 'single_choice', '下列何者非屬成文法法源？', '["議會自律規則", "國際條約", "一般法律原則", "行政規則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:48+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "406", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('pukao-d1056197-moex-00102', 'pukao-d1056197', 'pukao-d1056197-moex-112-d1a761c9', 'sub-pukao-d1056197-01', NULL, 'single_choice', '關於法規命令之訂定與生效，下列敘述何者錯誤？', '["法規命令依法應經上級機關核定者，於核定後始得發布", "法規命令之發布，應刊登於政府公報或新聞紙", "任何人得於公告期間內針對法規命令之草案提出意見", "法規命令乃行政權行使，受司法違憲之審查，惟不受立法權之審查"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:48+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "406", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('pukao-d1056197-moex-00103', 'pukao-d1056197', 'pukao-d1056197-moex-112-d1a761c9', 'sub-pukao-d1056197-01', NULL, 'single_choice', '下列何者非屬行政程序法明定之一般法律原則？', '["對等互惠原則", "誠實信用原則", "比例原則", "平等原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:48+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "406", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('pukao-d1056197-moex-00104', 'pukao-d1056197', 'pukao-d1056197-moex-112-d1a761c9', 'sub-pukao-d1056197-01', NULL, 'single_choice', '行政機關對於法律構成要件之涵攝，除有明顯瑕疵外，行政法院應予尊重之情形，為下列何者？', '["裁量收縮至零", "裁量瑕疵", "判斷餘地", "計畫裁量"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:48+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "406", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('pukao-d1056197-moex-00105', 'pukao-d1056197', 'pukao-d1056197-moex-112-d1a761c9', 'sub-pukao-d1056197-01', NULL, 'single_choice', '關於給付行政之敘述，下列何者正確？', '["給付行政全屬公權力之行使，均為公法事件", "農民健康保險之給付事項屬給付行政，為公法事件", "給付行政與干涉行政相同，均受嚴格之法律保留原則所拘束", "金融機構辦理清寒學生助學貸款，屬公法性質之給付行政"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:48+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "406", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('pukao-d1056197-moex-00106', 'pukao-d1056197', 'pukao-d1056197-moex-112-d1a761c9', 'sub-pukao-d1056197-01', NULL, 'single_choice', '某公立高中學生無照騎乘機車，受記大過一次之處分。其不服時，依司法院大法官解釋，得提起何種之救濟？', '["得依法提起相應之行政爭訟程序", "因非屬退學或類此之處分，故不得提起救濟", "只得依循校內救濟途徑提起救濟", "應依民事程序請求救濟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:48+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "406", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "僑務行政"}'::jsonb, NULL)
